module counter_8bit_updown(
    input clk,
    input reset,
    input up_down,
    output reg [7:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk or posedge reset) begin
    if (reset)
        count <= 8'b00000000;
    else if (up_down)
        count <= count + 1;
    else
        count <= count - 1;
end

endmodule
